import React, { useState } from 'react'
import PaymentForm from './PaymentForm';
import {  Radio, Space } from 'antd';

const PaymentBody = ({setViewPage}:any) => {

  const [value, setValue] = useState(1);
  const [selectedValue, setSelectedValue] = useState(1);

  const handleChange = (e:any) => {
    setSelectedValue(e.target.value);
  };

  return (
    <div className="PaymentBody">
          <div className="PaymentBody_Left">
          <Radio.Group name="radiogroup" value={selectedValue} onChange={handleChange} >
          <Space direction="vertical">

      <Radio value={1}>
        <span>A</span> <div>  {selectedValue === 1 && 'hello'} </div>
      </Radio>
      <Radio value={2}>
        <span>B</span> {selectedValue === 2 && 'hello'}
      </Radio>
      <Radio value={3}>
        <span>C</span> {selectedValue === 3 && 'hello'}
      </Radio>
      <Radio value={4}>
        <span>D</span> {selectedValue === 4 && 'hello'}
      </Radio>
      </Space>
    </Radio.Group>


           </div>
            <div className='PaymentBody_Right'>
             <PaymentForm/>
            </div>
    </div>
  )
}

export default PaymentBody
